Pseudo-code (editor key handler):
```rust
match event {
    KeyEvent { key: 'g' | 'G', ctrl: true, .. } => {
        let current_line = doc.cursor().line() + 1; // 1-based
        let max_line = doc.line_count();
        dialogs::open_goto_line(current_line, max_line, move |line| {
            let line = line.clamp(1, max_line);
            let line_idx = line - 1;
            doc.move_cursor_to(LineCol { line: line_idx, col: desired_col });
            editor.center_line_in_view(line_idx);
        });
    }
    _ => {}
}
